package github.chains;

import spoon.reflect.declaration.CtMethod;
import spoon.reflect.declaration.CtType;
import spoon.reflect.reference.CtTypeReference;
import spoon.support.compiler.jdt.JDTBasedSpoonCompiler;
import spoon.reflect.code.CtInvocation;
import spoon.reflect.code.CtBlock;
import spoon.Launcher;
import spoon.reflect.code.CtTry;
import spoon.reflect.code.CtCatch;
import spoon.reflect.code.CtExpression;
import spoon.reflect.code.CtThrow;
import spoon.reflect.declaration.CtClass;
import spoon.reflect.declaration.CtParameter;
import spoon.reflect.factory.Factory;
import spoon.reflect.visitor.filter.TypeFilter;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        Launcher launcher = new Launcher();

        // Set the source input directory
        launcher.addInputResource("src/main/java");

        // Set the output directory
        launcher.getEnvironment().setSourceOutputDirectory("target/spooned");

        // Compile the source code to create the model
        launcher.buildModel();

        // Get the factory
        Factory factory = launcher.getFactory();

        // Find all methods that call readValue with ObjectMapper
        List<CtMethod<?>> methods = factory.Package().getRootPackage().getElements(new TypeFilter<>(CtMethod.class));

        for (CtMethod<?> method : methods) {
            // Look for try-catch blocks that catch StreamReadException
            List<CtTry> tryBlocks = method.getElements(new TypeFilter<>(CtTry.class));

            for (CtTry tryBlock : tryBlocks) {
                // Check if the try block catches StreamReadException
                for (CtCatch catchBlock : tryBlock.getCatchBlocks()) {
                    CtTypeReference<? extends Throwable> catchType = catchBlock.getParameter().getType();

                    // Check if the catch block catches the old StreamReadException
                    if (catchType.getQualifiedName().equals("com.fasterxml.jackson.core.exc.StreamReadException")) {
                        // Replace with the new exception type
                        catchType.setSimpleName("JsonProcessingException");
                        catchType.setPackage(factory.Package().getOrCreate("com.fasterxml.jackson.core");
                    }
                }
            }
        }

        // Save the changes
        launcher.prettyprint();
    }
}

